local function prongsFun()
    local rigFun = rig()
    local holoFun = holo { Vector(0, 20, 56), Angle(-50, 90, 180), "models/props_combine/combine_bridge.mdl", Vector(0.14, 0.04, 0.08), color = mainColor, material = metalMat }
    local part = 360 / 3
    return function()
        local rg = rigFun()
        if !rg then return end
        for i=0, 3 do
            local ang = i * part
            local mdl = holoFun()
            if !mdl then goto cont end
            mdl:setParent(rg)
            rg:setAngles(Angle(ang, 0, 0))
            ::cont::
        end
        return rg
    end
end

local function circleProperty(radiusX, radiusY, layer)
    radiusY = radiusY or radiusX
    return {
        set = function(ent, toSet)
            if toSet == 1 then
                toSet = 0
            end
            local process = toSet * math.pi * 2
            local sin, cos = math.sin(process), math.cos(process)
            ent:setLocalPosLayer(layer, Vector(sin * radiusX, 0, cos * radiusY))
            ent.circleAng = toSet
        end,
        get = function(ent)
            return ent.circleAng or 0
        end
    }
end


